#include <bits/stdc++.h>
using namespace std;

const int N=102;

int n,m,a[N][N],f[N][N],p[N][N],path[N],cnt,ans=0x1f1f1f1f;

void init(int u,int v){
    if(!p[u][v])
        return;
    init(u,p[u][v]);
    path[++cnt]=p[u][v];
    init(p[u][v],v);
}

int main(){
    memset(f,0x1f,sizeof(f));
    memset(a,0x1f,sizeof(a));
    scanf("%d%d",&n,&m);
    for(int i=0,u,v,w;i<m;i++){
        scanf("%d%d%d",&u,&v,&w);
        f[u][v]=f[v][u]=min(f[u][v],w);
        a[u][v]=a[v][u]=f[u][v];
    }
    for(int i=1;i<=n;i++)
        f[i][i]=0;
    for(int k=1;k<=n;k++){
        for(int i=1;i<=n;i++)
            for(int j=i+1;j<=n;j++)
                if(a[i][k]+a[k][j]+f[i][j]<ans){
                    ans=a[i][k]+a[k][j]+f[i][j];
                    path[1]=i;
                    cnt=1;
                    init(i,j);
                    path[++cnt]=j;
                    path[++cnt]=k;
                }
        for(int i=1;i<=n;i++)
            for(int j=1;j<=n;j++)
                if(f[i][k]+f[k][j]<f[i][j])
                    f[i][j]=f[i][k]+f[k][j],p[i][j]=k;
    }
    if(!cnt)
        printf("No solution.");
    else
        for(int i=1;i<=cnt;i++){
            if(i<cnt)
                printf("%d ",path[i]);
            else
                printf("%d",path[i]);
        }
    return 0;
}
